// Deploy to 1v1_cehua1 pipeline
// 1. Tries existing cookies; if expired, opens headed for user login
// 2. Triggers pipeline with dest=1v1_cehua1
// 3. Monitors until build completes

import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const WORKSPACE_DIR = path.resolve(__dirname, '..');
const COOKIES_FILE = path.join(WORKSPACE_DIR, 'devops_cookies.json');
const PIPELINE_URL = 'https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/p-f78c977835c84b71a6d58b4746cd1c4a';
const DEST = '1v1_cehua1';

function log(msg) { console.log(`[DEPLOY] ${new Date().toISOString()} ${msg}`); }
async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

async function loadCookies(ctx) {
  const raw = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));
  const cookies = raw.map(c => ({
    name: c.name, value: c.value, domain: c.domain, path: c.path,
    httpOnly: c.httpOnly || false, secure: c.secure || false, sameSite: c.sameSite || 'Lax',
    expires: c.expires || -1,
  }));
  await ctx.addCookies(cookies);
  log(`已加载 ${cookies.length} 个 Cookie`);
}

async function verifyLogin(page) {
  const url = page.url();
  const content = await page.content();
  if (url.includes('login') || url.includes('auth') || content.includes('登录') || content.includes('飞书')) {
    return false;
  }
  return true;
}

async function waitForLogin(page) {
  log('❌ Cookie 已过期，请在浏览器窗口中登录...');
  log('提示：浏览器已打开在 headed 模式，请扫码或密码登录');

  // Wait for URL to no longer be login page, up to 5 minutes
  for (let i = 0; i < 300; i++) {
    await sleep(1000);
    const url = page.url();
    const content = await page.content();
    if (!url.includes('login') && !url.includes('auth') && !content.includes('登录界面')) {
      log('✅ 登录成功！');
      return true;
    }
    // If we got redirected away from login pattern
    if (!url.includes('login') && !url.includes('auth') && url.includes('devops')) {
      log('✅ 登录成功，已重定向回 DevOps！');
      return true;
    }
    if (i % 30 === 0) log(`等待登录中... (${Math.floor(i/60)}分${i%60}秒)`);
  }
  log('❌ 登录超时');
  return false;
}

async function triggerPipeline(page) {
  // Click "启动新构建"
  log('点击「启动新构建」...');
  const startBtn = await page.$('button:has-text("启动新构建")');
  if (!startBtn) {
    // Try to find it differently
    const btns = await page.$$('button');
    let found = false;
    for (const btn of btns) {
      const txt = ((await btn.textContent()) || '').replace(/\s+/g, '');
      if (txt.includes('启动新构建') || txt.includes('启动新')) {
        await btn.click();
        found = true;
        log('找到并点击了启动新构建按钮');
        break;
      }
    }
    if (!found) {
      log('❌ 未找到「启动新构建」按钮');
      await page.screenshot({ path: path.join(WORKSPACE_DIR, 'deploy_no_button.png'), fullPage: true });
      return false;
    }
  } else {
    await startBtn.click();
  }
  await sleep(3000);

  // Find the dest select dropdown and change value
  log(`设置 dest 为 ${DEST}...`);

  // Try clicking the select to open dropdown
  const selectTrigger = await page.$('.ant-select-selector, .ant-select-selection-item, [class*="select"]');

  // Better approach: find the input/combobox or select element
  // Look for Ant Design Select component
  const selectWrapper = await page.$('.ant-select');
  if (selectWrapper) {
    await selectWrapper.click();
    await sleep(1000);

    // Now select the option
    const option = await page.$(`[class*="ant-select-item-option"]:has-text("${DEST}")`);
    if (option) {
      await option.click();
      log(`已选择 ${DEST}`);
    } else {
      log(`未找到 ${DEST} 选项，尝试输入...`);
      // Try typing into the select search input
      const searchInput = await page.$('.ant-select-selection-search-input');
      if (searchInput) {
        await searchInput.click();
        await searchInput.fill('');
        await searchInput.type(DEST);
        await sleep(500);
        const matchedOption = await page.$(`[class*="ant-select-item-option"]`);
        if (matchedOption) {
          await matchedOption.click();
          log(`通过搜索选择了 ${DEST}`);
        }
      }
    }
  } else {
    log('未找到 Ant Design Select，检查是否有其他选择器...');
    // Maybe it's a native select?
    const nativeSelect = await page.$('select');
    if (nativeSelect) {
      await nativeSelect.selectOption(DEST);
      log(`已通过 native select 选择 ${DEST}`);
    }
  }
  await sleep(1000);

  // Check current dest value
  const destDisplay = await page.$('.ant-select-selection-item');
  if (destDisplay) {
    log(`当前选择: "${await destDisplay.textContent()}"`);
  }

  // Click the confirm/execute button
  log('点击「执行」按钮...');
  const allButtons = await page.$$('button');
  let execBtn = null;
  for (const btn of allButtons) {
    const text = ((await btn.textContent()) || '').replace(/\s+/g, '');
    if (text === '执行' || text === '确定' || text === '提交' || text === '运行' || text === '确认' || text.includes('执行')) {
      execBtn = btn;
      log(`找到执行按钮: "${await btn.textContent()}"`);
      break;
    }
  }

  if (!execBtn) {
    execBtn = await page.$('button.ant-btn-primary');
    if (execBtn) {
      log(`找到主按钮: "${await execBtn.textContent()}"`);
    }
  }

  if (execBtn) {
    await execBtn.click();
    log('✅ 已点击执行按钮！');
    await sleep(3000);
    return true;
  } else {
    log('❌ 找不到执行按钮');
    await page.screenshot({ path: path.join(WORKSPACE_DIR, 'deploy_no_exec_btn.png'), fullPage: true });
    return false;
  }
}

async function monitorBuild(page) {
  log('开始监控构建状态...');

  // Wait a bit for build to start, then check page
  await sleep(10000);

  // Go to pipeline page (reload to see new build)
  await page.goto(PIPELINE_URL, { waitUntil: 'networkidle', timeout: 30000 }).catch(() => {});
  await sleep(3000);
  log(`当前页面: ${page.url()}`);

  let result = 'unknown';
  for (let i = 0; i < 60; i++) { // 10 min max
    await sleep(10000);
    const text = await page.evaluate(() => document.body.innerText);
    log(`状态检查 ${i+1}/60`);

    // Check for various status indicators
    if (text.includes('构建成功') || /成功/.test(text) && !/(失败|错误)/.test(text)) {
      const svgCheck = await page.$('[class*="success"], [class*="passed"], [class*="check"]');
      if (svgCheck || text.includes('构建成功')) {
        result = 'success';
        log('✅ 构建成功！');
        break;
      }
    }

    if (text.includes('构建失败') || text.includes('失败') || text.includes('错误')) {
      const failEl = await page.$('[class*="fail"], [class*="error"]');
      if (failEl || text.includes('构建失败')) {
        result = 'failed';
        log('❌ 构建失败');
        break;
      }
    }

    // Check if still running
    if (text.includes('运行中') || text.includes('排队') || text.includes('等待')) {
      log('  构建运行中...');
    } else if (text.includes('未运行')) {
      log('  构建未启动，可能还在队列');
    }

    await page.reload({ waitUntil: 'networkidle', timeout: 30000 }).catch(() => {});
    await sleep(2000);
  }

  await page.screenshot({ path: path.join(WORKSPACE_DIR, 'deploy_final_result.png'), fullPage: true });
  return result;
}

async function main() {
  log(`开始部署 ${DEST}`);

  // Try headless first with existing cookies
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({
    viewport: { width: 1920, height: 1080 },
    locale: 'zh-CN',
    ignoreHTTPSErrors: true,
  });
  const page = await context.newPage();

  let cookiesExist = fs.existsSync(COOKIES_FILE);

  if (cookiesExist) {
    await loadCookies(context);
    log('正在验证 Cookie...');
    await page.goto(PIPELINE_URL, { waitUntil: 'networkidle', timeout: 30000 }).catch(() => {});
    await sleep(2000);

    const loggedIn = await verifyLogin(page);
    if (loggedIn) {
      log('✅ Cookie 有效！直接触发流水线。');
    } else {
      log('Cookie 过期，准备重登录。');
      await browser.close();
      cookiesExist = false;
    }
  }

  if (!cookiesExist) {
    log('🔄 打开浏览器窗口，请登录 DevOps...');
    await browser.close();

    // Open headed browser for login
    const loginBrowser = await chromium.launch({ headless: false, args: ['--no-sandbox'] });
    const loginContext = await loginBrowser.newContext({
      viewport: { width: 1920, height: 1080 },
      locale: 'zh-CN',
      ignoreHTTPSErrors: true,
    });
    const loginPage = await loginContext.newPage();

    log('打开 DevOps 登录页面...');
    await loginPage.goto(PIPELINE_URL, { waitUntil: 'domcontentloaded', timeout: 30000 }).catch(() => {});
    await sleep(2000);

    const loggedIn = await waitForLogin(loginPage);
    if (!loggedIn) {
      log('❌ 登录失败');
      await loginBrowser.close();
      process.exit(1);
    }

    // Save cookies
    const newCookies = await loginContext.cookies();
    fs.writeFileSync(COOKIES_FILE, JSON.stringify(newCookies, null, 2));
    log(`已保存 ${newCookies.length} 个 Cookie`);

    // Continue with this browser for pipeline trigger
    const triggerPage = loginPage;

    log('触发流水线...');
    const triggered = await triggerPipeline(triggerPage);
    if (!triggered) {
      await loginBrowser.close();
      process.exit(1);
    }

    log('监控构建状态...');
    const result = await monitorBuild(triggerPage);

    // Save final cookies
    const finalCookies = await loginContext.cookies();
    fs.writeFileSync(COOKIES_FILE, JSON.stringify(finalCookies, null, 2));

    await loginBrowser.close();

    if (result === 'success') {
      log(`✅ ${DEST} 更新成功！`);
      process.exit(0);
    } else if (result === 'failed') {
      log(`❌ ${DEST} 更新失败！`);
      process.exit(1);
    } else {
      log(`⚠️ ${DEST} 状态未知，请手动检查 DevOps 页面`);
      process.exit(2);
    }
  }

  // If we reach here, we're using headless + valid cookies
  log('触发流水线...');
  const triggered = await triggerPipeline(page);
  if (!triggered) {
    await browser.close();
    process.exit(1);
  }

  log('监控构建状态...');
  const result = await monitorBuild(page);

  // Save refreshed cookies
  const finalCookies = await context.cookies();
  fs.writeFileSync(COOKIES_FILE, JSON.stringify(finalCookies, null, 2));

  await browser.close();

  if (result === 'success') {
    log(`✅ ${DEST} 更新成功！`);
    process.exit(0);
  } else if (result === 'failed') {
    log(`❌ ${DEST} 更新失败！`);
    process.exit(1);
  } else {
    log(`⚠️ ${DEST} 状态未知，请手动检查 DevOps 页面`);
    process.exit(2);
  }
}

main().catch(err => {
  log(`错误: ${err.message}`);
  console.error(err.stack);
  process.exit(1);
});
